(function() {
  /*
   * PATCH v1.1.0 — Energy cost when traveling to other lands
   *
   * Cost table:  home 0 · meadow 10 · riverbank 15 · hillfarm 20 · lowland 25 · volcanic 35
   * Respects the Energy Cost toggle in the Pause menu.
   */
  var TRAVEL_ENERGY = {home:0,meadow:10,riverbank:15,hillfarm:20,lowland:25,volcanic:35};
  var _origTravelTo = window.travelTo;
  window.travelTo = function(landId) {
    if (landId === G.currentLand) { _origTravelTo(landId); return; }
    if (S.energyCost) {
      var cost = (TRAVEL_ENERGY[landId] !== undefined) ? TRAVEL_ENERGY[landId] : 15;
      if (cost > 0) {
        if (G.energy < cost) {
          toast('Not enough energy to travel! Need ' + cost + ' energy \u2014 sleep first. \uD83C\uDF19','error',3500);
          snd('error'); return;
        }
        G.energy = Math.max(0, G.energy - cost);
        if (typeof renderHUD === 'function') renderHUD();
        setTimeout(function() {
          var el = document.getElementById('tp-sub');
          if (el) el.textContent = '\u26A1 Used ' + cost + ' energy for the journey\u2026';
        }, 80);
      }
    }
    _origTravelTo(landId);
  };
  console.log('[Patcher v1.1.0] Travel energy cost patch applied.');
})();

(function() {
