(function() {
  /*
   * PATCH v1.1.1b — Mobile map fullscreen: SVG map on top, land list scrollable below
   */
  var _orig = window.buildMapFullscreen;
  window.buildMapFullscreen = function() {
    if (window.innerWidth > 680) { _orig(); return; }
    var body = document.getElementById('mf-body');
    var owned = G.lands || {};
    var totalRent = Object.entries(owned).reduce(function(s,e){
      var l=e[1];
      if (l.rented&&!l.owned){var p=LAND_PLOTS[e[0]];return s+(p?Math.round(p.rentDay*(1+(l.interestAccrued||0))):0);}
      return s;
    },0);
    var rentEl = document.getElementById('mf-rent-info');
    if (rentEl) rentEl.textContent = totalRent>0 ? '\u23F3 Rent: '+totalRent+'g/day' : '';
    var mapHtml = '<div style="position:relative;width:100%;aspect-ratio:16/9;border-radius:12px;overflow:hidden;border:2px solid var(--ui-border)">'+buildMapSVG(owned,false)+'</div>';
    var cards = '';
    if ((G.currentLand||'home') !== 'home') cards += '<button class="map-return-btn" onclick="travelTo(\'home\')">\uD83C\uDFE1 Return to Home Farm</button>';
    cards += '<div class="s-sec" style="margin-top:12px">\uD83D\uDDFA Available Land</div>';
    if (totalRent>0) cards += '<div style="padding:7px 10px;background:#fef9c3;border:1px solid #fde68a;border-radius:10px;font-size:10px;font-weight:700;color:#92400e;margin-bottom:8px">\u23F3 Active rent: <b>'+totalRent+'g/day</b> deducted each night</div>';
    var danger = Object.entries(owned).filter(function(e){return e[1].rented&&!e[1].owned&&(e[1].debtDays||0)>=5;});
    if (danger.length) cards += '<div class="mf-debt-warning">\uD83D\uDEA8 <b>DANGER!</b> '+danger.length+' plot(s) have missed rent 5+ days! Pay before day 7 or crops are seized!</div>';
    Object.entries(LAND_PLOTS).forEach(function(entry) {
      var id=entry[0],plot=entry[1],land=owned[id]||{};
      var io=land.owned,ir=land.rented&&!land.owned;
      var er=ir?Math.round(plot.rentDay*(1+(land.interestAccrued||0))):plot.rentDay;
      var hd=(land.debtG||0)>0,dd=land.debtDays||0,fc=plot.fertility.toLowerCase();
      cards+='<div class="land-card"><div class="land-card-top"><div class="land-card-left">';
      cards+='<span class="land-em">'+plot.e+'</span>';
      cards+='<div><div class="land-name">'+plot.n+' <span class="land-fert '+fc+'">'+plot.fertility+'</span></div></div>';
      cards+='</div></div>';
      cards+='<div class="land-desc">'+plot.desc+'</div>';
      cards+='<div class="land-price-row"><span class="land-price-tag">\uD83D\uDCB0 Buy: '+plot.buyPrice+'g</span><span class="land-rent-tag">\u00B7 Rent: '+plot.rentDay+'g/day</span><span class="land-interest-tag">(+'+Math.round(plot.interestRate*100)+'% interest/season)</span></div>';
      if (io) {
        cards+='<span class="land-owned-badge">\u2713 You own this land</span>';
        cards+='<div class="land-btn-row"><button class="land-btn map-travel-btn" onclick="travelTo(\''+id+'\')">\uD83D\uDE80 Go to this Farm</button></div>';
      } else if (ir) {
        var dw=dd>0?' \u00B7 \u23F0 '+(7-dd)+'d left':'';
        cards+='<span class="land-rented-badge">\u23F3 Renting \u00B7 '+er+'g/day'+(hd?' \u00B7 \u26A0\uFE0F Debt: '+Math.round(land.debtG)+'g'+dw:'')+' </span>';
        cards+='<div class="land-btn-row">';
        cards+='<button class="land-btn land-btn-buy" id="mfbl-'+id+'" '+(G.gold>=plot.buyPrice?'':'disabled')+'>Buy Out '+plot.buyPrice+'g</button>';
        cards+='<button class="land-btn land-btn-leave" id="mfll-'+id+'">Leave Plot</button>';
        cards+='<button class="land-btn map-travel-btn" onclick="travelTo(\''+id+'\')">\uD83D\uDE80 Go Here</button>';
        cards+='</div>';
      } else {
        cards+='<div class="land-btn-row">';
        cards+='<button class="land-btn land-btn-buy" id="mfbl-'+id+'" '+(G.gold>=plot.buyPrice?'':'disabled')+'>Buy '+plot.buyPrice+'g</button>';
        cards+='<button class="land-btn land-btn-rent" id="mfrl-'+id+'" '+(G.gold>=plot.rentDay?'':'disabled')+'>Rent '+plot.rentDay+'g/day</button>';
        cards+='</div>';
      }
      cards+='</div>';
    });
    cards+='<div class="market-note" style="margin-top:8px;margin-bottom:20px">\uD83D\uDCA1 <b>Land Tips:</b><br>Owned land is yours forever. Rented land charges daily \u2014 miss 7 days rent and crops are seized. Leave any rented plot anytime, debt forgiven.</div>';
    body.style.overflowY='auto';
    body.innerHTML='<div style="padding:12px 12px 8px">'+mapHtml+'</div><div style="padding:0 12px 16px">'+cards+'</div>';
    Object.keys(LAND_PLOTS).forEach(function(id){
      var bl=document.getElementById('mfbl-'+id),rl=document.getElementById('mfrl-'+id),ll=document.getElementById('mfll-'+id);
      if(bl)bl.addEventListener('click',function(){buyLand(id);buildMapFullscreen();});
      if(rl)rl.addEventListener('click',function(){rentLand(id);buildMapFullscreen();});
      if(ll)ll.addEventListener('click',function(){leaveLand(id);buildMapFullscreen();});
    });
  };
  console.log('[Patcher v1.1.1b] Mobile map layout patch applied.');
})();

(function() {
  /*
   * PATCH v1.1.2 — Soil-Crop Growth System
   *
   * Crop growth speed is now tied to land fertility. The days-needed
   * threshold is multiplied per land — more fertile = fewer days to ready.
   *
   *  Land        Multiplier   Effect
   *  ──────────────────────────────────────────
   *  home        1.00x        Baseline
   *  meadow      1.22x        22% slower (poor dry soil)
   *  riverbank   0.97x        3% faster  (moist average soil)
   *  hillfarm    0.90x        10% faster (elevated sun exposure)
   *  lowland     0.78x        22% faster (deep rich alluvial)
   *  volcanic    0.63x        37% faster (mineral-rich ash)
   *
   * Crop-soil affinity: native crops grow an extra 20% faster on
   * their home soil, stacked on top of the base bonus above.
   *
   *  meadow    → garlic, mushroom, tulip, parsnip
   *  riverbank → strawberry, blueberry, cranberry, carrot
   *  hillfarm  → potato, cauliflower, corn, sunflower
   *  lowland   → melon, pumpkin, eggplant, yam
   *  volcanic  → pepper, tomato, eggplant, cranberry
   *
   * No save-format changes. crop.days is still a raw counter;
   * only the ready threshold is adjusted per land in cropStage().
   */

  var SOIL_MULT = {
    home:      1.00,
    meadow:    1.22,
    riverbank: 0.97,
    hillfarm:  0.90,
    lowland:   0.78,
    volcanic:  0.63
  };

  var AFFINITY = {
    meadow:    ['garlic','mushroom','tulip','parsnip'],
    riverbank: ['strawberry','blueberry','cranberry','carrot'],
    hillfarm:  ['potato','cauliflower','corn','sunflower'],
    lowland:   ['melon','pumpkin','eggplant','yam'],
    volcanic:  ['pepper','tomato','eggplant','cranberry']
  };

  var AFFINITY_EXTRA = 0.80; // native crops get an extra 20% speedup

  /* ── Core: adjusted days needed for crop on a given land ── */
  window.getEffectiveDays = function(cropType, landId) {
    if (!CROPS[cropType]) return 1;
    var base = CROPS[cropType].days;
    var mult = (SOIL_MULT[landId] !== undefined) ? SOIL_MULT[landId] : 1.00;
    if ((AFFINITY[landId] || []).indexOf(cropType) !== -1) mult *= AFFINITY_EXTRA;
    return Math.max(1, Math.round(base * mult));
  };

  /* ── Override cropStage: use soil-adjusted threshold ── */
  window.cropStage = function(c) {
    if (!c) return -1;
    var d = getEffectiveDays(c.type, G.currentLand || 'home');
    if (c.days >= d)                   return 3;
    if (c.days >= Math.ceil(d * 0.66)) return 2;
    if (c.days >= Math.ceil(d * 0.33)) return 1;
    return 0;
  };

  /* ── renderFarm wrapper: fix days-badge to show adjusted remaining days ── */
  var _origRF = window.renderFarm;
  window.renderFarm = function() {
    _origRF();
    var landId = G.currentLand || 'home';
    if (landId === 'home') return; // mult is 1.0, badge already correct
    var grid = document.getElementById('farm-grid');
    if (!grid) return;
    for (var r = 0; r < GH; r++) {
      for (var c = 0; c < GW; c++) {
        var el = grid.children[r * GW + c];
        if (!el) continue;
        var tile = G.farm[r] && G.farm[r][c];
        if (!tile || !tile.crop) continue;
        if (cropStage(tile.crop) === 3) continue; // already ready, no badge
        var badge = el.querySelector('.days-badge');
        if (!badge) continue;
        var rem = Math.max(0, getEffectiveDays(tile.crop.type, landId) - tile.crop.days);
        badge.textContent = Math.ceil(rem) + 'd';
      }
    }
  };

  /* ── renderLandBanner wrapper: append growth speed indicator ── */
  var _origRLB = window.renderLandBanner;
  window.renderLandBanner = function() {
    _origRLB();
    var cl = G.currentLand || 'home';
    if (cl === 'home') return;
    var banner = document.getElementById('land-banner');
    if (!banner || !banner.classList.contains('show')) return;
    var mult = SOIL_MULT[cl] || 1.0;
    var pct  = Math.round(Math.abs(1 - mult) * 100);
    if (!pct) return;
    var lbl = mult < 1.0
      ? ' \u00B7 \u26A1 +' + pct + '% faster crops'
      : ' \u00B7 \uD83D\uDC22 \u2212' + pct + '% slower crops';
    if (banner.textContent.indexOf('faster') === -1 && banner.textContent.indexOf('slower') === -1) {
      banner.textContent += lbl;
    }
  };

  /* ── Helper: build soil info HTML snippet for a land card ── */
  function _soilTag(landId) {
    var mult = SOIL_MULT[landId] || 1.0;
    var affs = AFFINITY[landId] || [];
    var pct  = Math.round(Math.abs(1 - mult) * 100);
    var parts = [];
    if (pct > 0) {
      parts.push(mult < 1.0
        ? '<span style="color:#16a34a;font-weight:800">\u26A1 +' + pct + '% faster growth</span>'
        : '<span style="color:#b45309;font-weight:800">\uD83D\uDC22 \u2212' + pct + '% slower growth</span>');
    }
    if (affs.length) {
      var ems   = affs.map(function(t){ return CROPS[t] ? CROPS[t].e : ''; }).join('');
      var names = affs.map(function(t){ return CROPS[t] ? CROPS[t].n : t; }).join(', ');
      parts.push('<span style="color:var(--text-muted)" title="Native crops grow an extra 20% faster here: ' + names + '">\uD83C\uDF1F Native: ' + ems + '</span>');
    }
    if (!parts.length) return '';
    return '<div class="soil-growth-tag" style="display:flex;gap:6px;align-items:center;flex-wrap:wrap;margin:3px 0 4px;padding:3px 0;font-size:10px;border-top:1px dashed var(--ui-border)">'
      + parts.join('<span style="opacity:.35"> \u00B7 </span>')
      + '</div>';
  }

  /* ── buildMap wrapper: inject soil tag into side-panel land cards ── */
  var _origBM = window.buildMap;
  window.buildMap = function() {
    var html = _origBM();
    Object.entries(LAND_PLOTS).forEach(function(entry) {
      var id = entry[0], plot = entry[1];
      var tag = _soilTag(id);
      if (!tag) return;
      var anchor = '<div class="land-desc">' + plot.desc + '</div>';
      html = html.replace(anchor, anchor + tag);
    });
    return html;
  };

  /* ── buildMapFullscreen wrapper: inject soil tag into fullscreen land cards ── */
  var _origBMF = window.buildMapFullscreen;
  window.buildMapFullscreen = function() {
    _origBMF();
    var body = document.getElementById('mf-body');
    if (!body) return;
    var descs  = body.querySelectorAll('.land-desc');
    var landIds = Object.keys(LAND_PLOTS);
    descs.forEach(function(desc, i) {
      var landId = landIds[i];
      if (!landId) return;
      if (desc.nextElementSibling && desc.nextElementSibling.classList.contains('soil-growth-tag')) return;
      var tag = _soilTag(landId);
      if (tag) desc.insertAdjacentHTML('afterend', tag);
    });
  };

  console.log('[Patcher v1.1.2] Soil-crop growth system applied.');
})();
